// HasJobWith applies the HasEdge predicate on the "job" edge with a given conditions (other predicates).
func HasJobWith(preds ...predicate.TransferJob) predicate.TransferJobFile {
	return predicate.TransferJobFile(func(s *sql.Selector) {
		step := newJobStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.TransferJobFile) predicate.TransferJobFile {
	return predicate.TransferJobFile(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.TransferJobFile) predicate.TransferJobFile {
	return predicate.TransferJobFile(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.TransferJobFile) predicate.TransferJobFile {
	return predicate.TransferJobFile(sql.NotPredicates(p))
}
